1	import { describe, it } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { existsSync, readFileSync } from 'node:fs';
4	import { resolve, dirname } from 'node:path';
5	import { fileURLToPath } from 'node:url';
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	const ROOT = resolve(__dirname, '..');  // kanban/ root
9	
10	function readPkg(rel) {
11	  return JSON.parse(readFileSync(resolve(ROOT, rel), 'utf-8'));
12	}
13	
14	// ── Subtask 1: Root package.json ─────────────────────────────────────────────
15	describe('Root package.json', () => {
16	  it('file exists', () => assert.ok(existsSync(resolve(ROOT, 'package.json'))));
17	  it('has private: true',       () => assert.equal(readPkg('package.json').private, true));
18	  it('has name "kanban-app"',   () => assert.equal(readPkg('package.json').name, 'kanban-app'));
19	  it('has version "1.0.0"',     () => assert.equal(readPkg('package.json').version, '1.0.0'));
20	  it('workspaces contains "client"', () => assert.ok(readPkg('package.json').workspaces?.includes('client')));
21	  it('workspaces contains "server"', () => assert.ok(readPkg('package.json').workspaces?.includes('server')));
22	});
23	
24	// ── Subtask 2: npm scripts & concurrently ────────────────────────────────────
25	describe('Root npm scripts', () => {
26	  it('has scripts.dev', () => assert.ok(readPkg('package.json').scripts?.dev));
27	  it('scripts.dev uses concurrently', () => assert.match(readPkg('package.json').scripts.dev, /concurrently/));
28	  it('scripts.dev references client dev', () => assert.match(readPkg('package.json').scripts.dev, /client/));
29	  it('scripts.dev references server dev', () => assert.match(readPkg('package.json').scripts.dev, /server/));
30	  it('has scripts.build', () => assert.ok(readPkg('package.json').scripts?.build));
31	  it('has scripts.start', () => assert.ok(readPkg('package.json').scripts?.start));
32	  it('devDependencies includes concurrently', () =>
33	    assert.ok(readPkg('package.json').devDependencies?.concurrently));
34	});
35	
36	// ── Subtask 3: Directory structure ───────────────────────────────────────────
37	describe('Directory structure', () => {
38	  const dirs = [
39	    'client',
40	    'client/src',
41	    'server',
42	    'server/db',
43	    'server/api',
44	    'server/ws',
45	  ];
46	  for (const dir of dirs) {
47	    it(`directory exists: ${dir}`, () =>
48	      assert.ok(existsSync(resolve(ROOT, dir)), `Missing: kanban/${dir}/`));
49	  }
50	});
51	
52	// ── Subtask 4: Workspace package.json files ──────────────────────────────────
53	describe('Client package.json', () => {
54	  it('file exists', () => assert.ok(existsSync(resolve(ROOT, 'client/package.json'))));
55	  it('name is "kanban-client"', () => assert.equal(readPkg('client/package.json').name, 'kanban-client'));
56	  it('has scripts.dev',     () => assert.ok(readPkg('client/package.json').scripts?.dev));
57	  it('has scripts.build',   () => assert.ok(readPkg('client/package.json').scripts?.build));
58	  it('has scripts.preview', () => assert.ok(readPkg('client/package.json').scripts?.preview));
59	});
60	
61	describe('Server package.json', () => {
62	  it('file exists', () => assert.ok(existsSync(resolve(ROOT, 'server/package.json'))));
63	  it('name is "kanban-server"', () => assert.equal(readPkg('server/package.json').name, 'kanban-server'));
64	  it('has scripts.dev',   () => assert.ok(readPkg('server/package.json').scripts?.dev));
65	  it('has scripts.start', () => assert.ok(readPkg('server/package.json').scripts?.start));
66	});
